use super::super::validate::navigation::{NavigationYaml, RouteYaml};
use std::fmt::Write as _;
use std::fs;
use std::path::{Path, PathBuf};

pub fn generate_typescript_routes(nav: &NavigationYaml) -> String {
    let mut out = String::new();
    out.push_str(
        "// src/navigation/__generated__/route-types.ts\n\
         // This file is generated by k1s0 generate navigation.\n\
         // Do not edit manually.\n\n",
    );

    let all_routes = collect_all_routes_flat(&nav.routes);

    out.push_str("export const RouteIds = {\n");
    for route in &all_routes {
        let const_name = route.id.to_uppercase();
        writeln!(out, "  {const_name}: '{}',", route.id).expect("writing to String cannot fail");
    }
    out.push_str("} as const;\n\n");

    out.push_str("export type RouteId = typeof RouteIds[keyof typeof RouteIds];\n\n");
    out.push_str("export type RouteParams = {\n");
    for route in &all_routes {
        if route.params.is_empty() {
            writeln!(out, "  {}: Record<string, never>;", route.id)
                .expect("writing to String cannot fail");
        } else {
            write!(out, "  {}: {{ ", route.id).expect("writing to String cannot fail");
            let params = route
                .params
                .iter()
                .map(|param| {
                    format!(
                        "{}: {}",
                        param.name,
                        typescript_param_type(&param.param_type)
                    )
                })
                .collect::<Vec<_>>()
                .join("; ");
            out.push_str(&params);
            out.push_str(" };\n");
        }
    }
    out.push_str("};\n");

    out
}

pub fn generate_dart_routes(nav: &NavigationYaml) -> String {
    let mut out = String::new();
    out.push_str(
        "// lib/navigation/__generated__/route_ids.dart\n\
         // This file is generated by k1s0 generate navigation.\n\
         // Do not edit manually.\n\n",
    );

    let all_routes = collect_all_routes_flat(&nav.routes);

    out.push_str("enum RouteId {\n");
    for (index, route) in all_routes.iter().enumerate() {
        let camel = to_camel_case(&route.id);
        let suffix = if index + 1 == all_routes.len() {
            ";"
        } else {
            ","
        };
        writeln!(out, "  {camel}{suffix}").expect("writing to String cannot fail");
    }

    out.push_str("\n  String get path => switch (this) {\n");
    for route in &all_routes {
        let camel = to_camel_case(&route.id);
        writeln!(out, "    RouteId.{camel} => '{}',", route.full_path)
            .expect("writing to String cannot fail");
    }
    out.push_str("  };\n");
    out.push_str("}\n");

    out
}

struct FlatRoute {
    id: String,
    full_path: String,
    params: Vec<FlatParam>,
}

struct FlatParam {
    name: String,
    param_type: String,
}

fn collect_all_routes_flat(routes: &[RouteYaml]) -> Vec<FlatRoute> {
    let mut result = Vec::new();
    collect_routes_recursive(routes, "", &mut result);
    result
}

fn collect_routes_recursive(routes: &[RouteYaml], parent_path: &str, out: &mut Vec<FlatRoute>) {
    for route in routes {
        let full_path = if route.path.starts_with('/') || parent_path.is_empty() {
            route.path.clone()
        } else {
            format!("{}/{}", parent_path.trim_end_matches('/'), route.path)
        };

        out.push(FlatRoute {
            id: route.id.clone(),
            full_path: full_path.clone(),
            params: route
                .params
                .iter()
                .map(|param| FlatParam {
                    name: param.name.clone(),
                    param_type: param.param_type.clone(),
                })
                .collect(),
        });

        collect_routes_recursive(&route.children, &full_path, out);
    }
}

fn typescript_param_type(param_type: &str) -> &'static str {
    match param_type {
        "int" => "number",
        _ => "string",
    }
}

fn to_camel_case(snake: &str) -> String {
    let mut result = String::new();
    let mut capitalize = false;
    for ch in snake.chars() {
        if ch == '_' {
            capitalize = true;
        } else if capitalize {
            result.push(ch.to_uppercase().next().unwrap_or(ch));
            capitalize = false;
        } else {
            result.push(ch);
        }
    }
    result
}

/// Generate TypeScript routes from a navigation file.
///
/// # Errors
///
/// Returns an error when the file cannot be read or parsed.
pub fn generate_typescript_routes_from_file(
    path: &str,
) -> Result<String, Box<dyn std::error::Error>> {
    let content = fs::read_to_string(path)?;
    let nav: NavigationYaml = serde_yaml::from_str(&content)?;
    Ok(generate_typescript_routes(&nav))
}

/// Generate Dart routes from a navigation file.
///
/// # Errors
///
/// Returns an error when the file cannot be read or parsed.
pub fn generate_dart_routes_from_file(path: &str) -> Result<String, Box<dyn std::error::Error>> {
    let content = fs::read_to_string(path)?;
    let nav: NavigationYaml = serde_yaml::from_str(&content)?;
    Ok(generate_dart_routes(&nav))
}

/// Write generated TypeScript routes to disk.
///
/// # Errors
///
/// Returns an error when the output directory cannot be created or the file cannot be written.
pub fn write_typescript_routes_file(
    nav: &NavigationYaml,
    output_dir: &Path,
) -> Result<PathBuf, Box<dyn std::error::Error>> {
    fs::create_dir_all(output_dir)?;
    let output_path = output_dir.join("route-types.ts");
    fs::write(&output_path, generate_typescript_routes(nav))?;
    Ok(output_path)
}

/// Write generated Dart routes to disk.
///
/// # Errors
///
/// Returns an error when the output directory cannot be created or the file cannot be written.
pub fn write_dart_routes_file(
    nav: &NavigationYaml,
    output_dir: &Path,
) -> Result<PathBuf, Box<dyn std::error::Error>> {
    fs::create_dir_all(output_dir)?;
    let output_path = output_dir.join("route_ids.dart");
    fs::write(&output_path, generate_dart_routes(nav))?;
    Ok(output_path)
}

/// Load a navigation file and write generated routes for each requested target.
///
/// # Errors
///
/// Returns an error when the file cannot be loaded or an output file cannot be written.
pub fn write_generated_routes_from_file(
    nav_path: &Path,
    output_dir: &Path,
    targets: &[&str],
) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
    let content = fs::read_to_string(nav_path)?;
    let nav: NavigationYaml = serde_yaml::from_str(&content)?;

    let mut written = Vec::new();
    for target in targets {
        match *target {
            "typescript" => written.push(write_typescript_routes_file(&nav, output_dir)?),
            "dart" => written.push(write_dart_routes_file(&nav, output_dir)?),
            other => return Err(format!("unsupported target: {other}").into()),
        }
    }

    Ok(written)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::commands::validate::navigation::{GuardYaml, NavigationYaml, ParamYaml, RouteYaml};

    fn sample_navigation() -> NavigationYaml {
        NavigationYaml {
            version: 1,
            guards: vec![GuardYaml {
                id: "auth_required".to_string(),
                guard_type: "auth_required".to_string(),
                redirect_to: "/login".to_string(),
                roles: vec![],
            }],
            routes: vec![
                RouteYaml {
                    id: "root".to_string(),
                    path: "/".to_string(),
                    component_id: None,
                    guards: vec![],
                    transition: None,
                    redirect_to: Some("/dashboard".to_string()),
                    children: vec![],
                    params: vec![],
                },
                RouteYaml {
                    id: "login".to_string(),
                    path: "/login".to_string(),
                    component_id: Some("LoginPage".to_string()),
                    guards: vec![],
                    transition: None,
                    redirect_to: None,
                    children: vec![],
                    params: vec![],
                },
                RouteYaml {
                    id: "dashboard".to_string(),
                    path: "/dashboard".to_string(),
                    component_id: Some("DashboardPage".to_string()),
                    guards: vec!["auth_required".to_string()],
                    transition: Some("fade".to_string()),
                    redirect_to: None,
                    children: vec![],
                    params: vec![],
                },
                RouteYaml {
                    id: "users".to_string(),
                    path: "/users".to_string(),
                    component_id: Some("UsersPage".to_string()),
                    guards: vec!["auth_required".to_string()],
                    transition: Some("slide".to_string()),
                    redirect_to: None,
                    children: vec![RouteYaml {
                        id: "user_detail".to_string(),
                        path: ":id".to_string(),
                        component_id: Some("UserDetailPage".to_string()),
                        guards: vec!["auth_required".to_string()],
                        transition: None,
                        redirect_to: None,
                        children: vec![],
                        params: vec![ParamYaml {
                            name: "id".to_string(),
                            param_type: "string".to_string(),
                        }],
                    }],
                    params: vec![],
                },
            ],
        }
    }

    #[test]
    fn test_generate_typescript_routes() {
        let nav = sample_navigation();
        let ts = generate_typescript_routes(&nav);
        assert!(ts.contains("export const RouteIds"));
        assert!(ts.contains("ROOT: 'root'"));
        assert!(ts.contains("LOGIN: 'login'"));
        assert!(ts.contains("DASHBOARD: 'dashboard'"));
        assert!(ts.contains("USERS: 'users'"));
        assert!(ts.contains("USER_DETAIL: 'user_detail'"));
        assert!(ts.contains("export type RouteId"));
        assert!(ts.contains("export type RouteParams"));
        assert!(ts.contains("user_detail: { id: string }"));
        assert!(ts.contains("root: Record<string, never>"));
    }

    #[test]
    fn test_generate_dart_routes() {
        let nav = sample_navigation();
        let dart = generate_dart_routes(&nav);
        assert!(dart.contains("enum RouteId"));
        assert!(dart.contains("root,"));
        assert!(dart.contains("login,"));
        assert!(dart.contains("dashboard,"));
        assert!(dart.contains("users,"));
        assert!(dart.contains("userDetail;"));
        assert!(dart.contains("String get path"));
        assert!(dart.contains("RouteId.root => '/'"));
        assert!(dart.contains("RouteId.userDetail => '/users/:id'"));
    }

    #[test]
    fn test_to_camel_case() {
        assert_eq!(to_camel_case("user_detail"), "userDetail");
        assert_eq!(to_camel_case("not_found"), "notFound");
        assert_eq!(to_camel_case("root"), "root");
        assert_eq!(to_camel_case("a_b_c"), "aBC");
    }
}
